/**
 * Google Maps Marker Component
 *
 * DRAGGING ARCHITECTURE:
 * =====================
 * This component supports TWO dragging modes:
 *
 * 1. NATIVE DRAGGING (Google Maps built-in)
 *    - Used when: draggable=true AND draggableDirections is NOT specified
 *    - How: Sets marker.gmpDraggable = true
 *    - Benefits: Simpler, uses Google's native drag implementation
 *    - Limitations: No directional constraints or distance constraints
 *
 * 2. MANUAL DRAGGING (Custom implementation)
 *    - Used when: draggable=true AND draggableDirections IS specified
 *    - How: Sets marker.gmpDraggable = false, implements custom mouse/keyboard handlers
 *    - Benefits: Supports constrained movement (horizontal/vertical only, min/max distance)
 *    - Implementation: See "MANUAL/CUSTOM DRAG IMPLEMENTATION" section below
 *
 * Code in this file is marked with comments:
 * - "General:" - Used by both modes or neither
 * - "Native dragging:" - Specific to native Google Maps dragging
 * - "Manual dragging:" - Specific to custom constrained dragging
 */

import React, { forwardRef, useEffect, useRef } from 'react'
import { css } from '@linaria/core'
import PropTypes from 'prop-types'
import { createPortal } from 'react-dom'

import colors from '../../shared/Marker/colors'
import TeardropMarker from '../../shared/Marker/TeardropMarker'
import RoundMarker from '../../shared/Marker/RoundMarker'
import ResizeHandleMarker from '../../shared/Marker/ResizeHandleMarker'
import useLibraries from '../hooks/useLibraries'
import useMap from '../../shared/hooks/useMap'
import useMarker from '../../shared/hooks/useMarker'
import { constrainPosition, draggableDirectionsValidator } from '../../shared/Marker/draggableDirectionsConstraints'
import {
  EDGE_PAN_THRESHOLD,
  KEYBOARD_DRAG_MOVEMENT_MS,
  KEYBOARD_DRAG_STEP_FACTOR,
  MAP_PAN_SCALE,
} from '../../shared/utils'

const ARIA_GRABBED = 'aria-grabbed'

// General: CSS class used during manual dragging to prevent pointer events on other markers
const markerClassName = css`
  .dragging & {
    pointer-events: none !important;
  }
`

// General: CSS class for draggable markers (used by both native and manual dragging)
const draggableMarkerClassName = css`
  &[${ARIA_GRABBED}='true'] {
    cursor: grabbing;
  }

  &[${ARIA_GRABBED}='false'] {
    cursor: grab !important; // Google sets the cursor to 'pointer', important is needed to override it.
  }
`

/**
 * General: Adds event listeners to the marker
 * Note: Native drag events (dragstart, drag, dragend) use addListener API
 * Other events use standard addEventListener
 */
function addEventListeners({ eventListeners, eventListenersRef, gmpEventListenersRef, marker }) {
  Object.entries(eventListeners).forEach(([event, handler]) => {
    if (event === 'click') {
      event = 'gmp-click'
    }

    // Native dragging: Google Maps drag events use the addListener API
    if (event.startsWith('drag')) {
      const listener = marker.addListener(event, handler)
      eventListenersRef.current.push(listener)
    } else {
      marker.addEventListener(event, handler)
      gmpEventListenersRef.current.push({ event, handler })
    }
  })
}

// General: Clears all event listeners from the marker
function clearEventListeners({ eventListenersRef, gmpEventListenersRef, marker }) {
  eventListenersRef.current.forEach((listener) => listener.remove())
  gmpEventListenersRef.current.forEach(({ event, handler }) => {
    marker?.removeEventListener(event, handler)
  })

  eventListenersRef.current = []
  gmpEventListenersRef.current = []
}

// General: Configures marker styling (colors and draggable cursor)
function configureMarkerStyling({ initialPropsRef, marker }) {
  const { fill, invertFill } = colors[initialPropsRef.current.color] || colors.red
  marker.style['--fill'] = fill
  marker.style['--invertFill'] = invertFill
  marker.classList.add(markerClassName)

  if (initialPropsRef.current.draggable) {
    marker.classList.add(draggableMarkerClassName)
  }
}

// General: Creates the content element for the marker
function createContentElement() {
  const contentElement = document.createElement('div')
  contentElement.style.lineHeight = 0

  return contentElement
}

/**
 * General: Creates initial options for the marker
 * Note: Native dragging is DISABLED if draggableDirections is present
 * (manual dragging will be used instead)
 */
function createInitialOptions({ contentRef, initialPropsRef, map }) {
  const options = {
    content: contentRef.current,
    gmpClickable: initialPropsRef.current.interactable,
    // Native dragging: Disabled when draggableDirections is present (manual drag used instead)
    gmpDraggable: initialPropsRef.current.draggable && !initialPropsRef.current.draggableDirections,
    map,
    position: { lat: initialPropsRef.current.latitude, lng: initialPropsRef.current.longitude },
  }

  if (initialPropsRef.current.title) {
    options.title = initialPropsRef.current.title
  }

  return options
}

// General: Updates marker accessibility attributes
function updateMarkerAccessibility({ ariaLabel, draggable, interactable, marker, title }) {
  marker.setAttribute('aria-label', ariaLabel)

  if (typeof title === 'string') {
    marker.setAttribute('title', title)
  }

  if (!interactable && !draggable) {
    // Google removes the role attribute when the marker changes from interactable to not interactable.
    // This allows use to add the role attribute back to the marker.
    requestAnimationFrame(() => {
      marker.setAttribute('role', 'img')
    })
  }
}

// General: Updates the draggable state (cursor styling)
function updateMarkerDraggableState({ draggable, marker }) {
  if (draggable) {
    marker.classList.add(draggableMarkerClassName)
  } else {
    marker.classList.remove(draggableMarkerClassName)
  }
}

// General: Updates marker translation for different marker types
function updateMarkerTranslate({ cluster, draggableDirections, imageSrc, marker, proximity }) {
  if (cluster || imageSrc || proximity || draggableDirections) {
    marker.style.translate = '0 50%'
  } else {
    marker.style.translate = 'none'
  }
}

/**
 * Manual dragging: Automatically pan the map when marker gets near the edge
 *
 * WHY THIS EXISTS:
 * When dragging a marker, users often need to move it beyond the visible map area.
 * Without auto-panning, the marker would hit the edge and stop, forcing users to:
 * 1. Stop dragging
 * 2. Pan the map manually
 * 3. Resume dragging
 * This is poor UX for a common workflow.
 *
 * WHAT IT DOES:
 * Checks if the marker is within EDGE_PAN_THRESHOLD pixels of any map edge.
 * If so, pans the map in that direction to keep the marker visible and allow continued dragging.
 * Pan speed is proportional to how close the marker is to the edge.
 */
function moveMapIfNearEdge({ map, marker }) {
  const mapDiv = map.getDiv()
  const bounds = mapDiv.getBoundingClientRect()
  const threshold = EDGE_PAN_THRESHOLD // px from edge to trigger pan

  // Get marker's current position
  const markerPosition = marker.position
  const markerLatitude = typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat
  const markerLongitude = typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng

  // Convert marker position to pixel coordinates
  const mapBounds = map.getBounds()
  const topRight = mapBounds.getNorthEast()
  const bottomLeft = mapBounds.getSouthWest()

  const markerX = ((markerLongitude - bottomLeft.lng()) / (topRight.lng() - bottomLeft.lng())) * bounds.width
  const markerY = ((topRight.lat() - markerLatitude) / (topRight.lat() - bottomLeft.lat())) * bounds.height

  let dx = 0
  let dy = 0

  if (markerX < threshold) {
    dx = markerX - threshold
  } else if (markerX > bounds.width - threshold) {
    dx = markerX - (bounds.width - threshold)
  }

  if (markerY < threshold) {
    dy = markerY - threshold
  } else if (markerY > bounds.height - threshold) {
    dy = markerY - (bounds.height - threshold)
  }

  if (dx !== 0 || dy !== 0) {
    const center = map.getCenter()
    const latitudePerPixel = (topRight.lat() - bottomLeft.lat()) / bounds.height
    const longitudePerPixel = (topRight.lng() - bottomLeft.lng()) / bounds.width

    setMapCenter({ center, dx, dy, latitudePerPixel, longitudePerPixel, map })
  }
}

/**
 * Manual dragging: Shared function to update marker position from client coordinates
 * Used by both mouse and touch drag handlers
 */
function updateMarkerFromClientCoordinates({
  clientX,
  clientY,
  constraintOriginRef,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  map,
  marker,
}) {
  if (!map) {
    return
  }

  const bounds = map.getDiv().getBoundingClientRect()
  const x = clientX - bounds.left
  const y = clientY - bounds.top

  // Use Google Maps API to convert pixel to latitude/longitude
  const topRight = map.getBounds().getNorthEast()
  const bottomLeft = map.getBounds().getSouthWest()

  // Simple latitude/longitude calculation
  const latitude = topRight.lat() - (y / bounds.height) * (topRight.lat() - bottomLeft.lat())
  const longitude = bottomLeft.lng() + (x / bounds.width) * (topRight.lng() - bottomLeft.lng())

  const newPosition = { latitude, longitude }

  const constrainedPosition = constrainPosition({
    draggableDirections,
    newPosition,
    originPosition: draggableConstraintOrigin || constraintOriginRef.current,
    maxDistance: draggableMaxDistance,
    minDistance: draggableMinDistance,
  })

  marker.position = {
    lat: constrainedPosition.latitude,
    lng: constrainedPosition.longitude,
  }
}

/**
 * Manual dragging: Creates mouse event handlers for manual drag with constraints
 * This is used when draggableDirections is specified to enable constrained movement
 */
function createManualDragHandlers({
  constraintOriginRef,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  draggingRef,
  libraries,
  map,
  mapContainer,
  marker,
  onDrag,
  onDragEnd,
  sharedPopper,
  skipNextClickRef,
}) {
  let mouseDown = false
  let lastClientX = 0
  let lastClientY = 0
  let animationFrameId = null
  let blurPreventionHandler = null

  function continuousUpdate() {
    if (mouseDown && draggingRef.current) {
      updateMarkerFromClientCoordinates({
        clientX: lastClientX,
        clientY: lastClientY,
        constraintOriginRef,
        draggableConstraintOrigin,
        draggableDirections,
        draggableMaxDistance,
        draggableMinDistance,
        map,
        marker,
      })

      // Update label position if a label is showing
      if (sharedPopper && sharedPopper.isLabelOpenRef.current) {
        const markerRect = marker.getBoundingClientRect()
        sharedPopper.update({
          event: {
            clientX: markerRect.left + markerRect.width / 2,
            clientY: markerRect.top + markerRect.height / 2,
          },
        })
      }

      if (onDrag) {
        const markerPosition = marker.position
        onDrag({
          position: {
            latitude: typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat,
            longitude: typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng,
          },
        })
      }

      // Pan map if marker is near edge during continuous update
      moveMapIfNearEdge({ map, marker })

      animationFrameId = requestAnimationFrame(continuousUpdate)
    }
  }

  function mouseMoveHandler(event) {
    if (!mouseDown || !map || !libraries) return

    lastClientX = event.clientX
    lastClientY = event.clientY

    if (!draggingRef.current) {
      draggingRef.current = true
      marker.setAttribute(ARIA_GRABBED, 'true')

      // Add dragging class to disable pointer events on markers
      if (mapContainer?.current) {
        mapContainer.current.classList.add('dragging')
      }

      /**
       * Manual dragging: Prevent blur during mouse drag
       *
       * WHY THIS IS NEEDED:
       * During drag, the marker can lose focus in two ways:
       * 1. When dragged out of view (partially or fully off-screen)
       * 2. When the mouse cursor moves too fast and leaves the marker element
       *
       * Without blur prevention:
       * - Keyboard users lose the ability to cancel drag with Escape
       * - Focus would move elsewhere, breaking the drag interaction
       * - Accessibility is severely degraded
       *
       * SOLUTION:
       * Intercept blur events during drag and immediately refocus the marker.
       * This keeps the marker focused even when it moves out of view or cursor leaves it.
       */
      blurPreventionHandler = (blurEvent) => {
        if (blurEvent.target === marker) {
          blurEvent.preventDefault()
          blurEvent.stopImmediatePropagation()
          requestAnimationFrame(() => {
            if (draggingRef.current) {
              marker.focus()
            }
          })
        }
      }

      marker.addEventListener('blur', blurPreventionHandler, { capture: true })

      // Start continuous update loop
      continuousUpdate()
    }

    // Pan map if marker is near edge
    moveMapIfNearEdge({ map, marker })
  }

  function mouseUpHandler(event) {
    if (!mouseDown) return

    mouseDown = false
    const wasDragging = draggingRef.current
    draggingRef.current = false
    marker.setAttribute(ARIA_GRABBED, 'false')

    // Remove blur prevention handler
    if (blurPreventionHandler) {
      marker.removeEventListener('blur', blurPreventionHandler, { capture: true })
      blurPreventionHandler = null
    }

    // Remove dragging class to re-enable pointer events on markers
    if (wasDragging && mapContainer?.current) {
      mapContainer.current.classList.remove('dragging')
    }

    // Cancel animation frame
    if (animationFrameId) {
      cancelAnimationFrame(animationFrameId)
      animationFrameId = null
    }

    /**
     * Manual dragging: Prevent map click after drag ends (skipNextClickRef)
     *
     * WHY THIS IS NEEDED:
     * When a user releases the mouse button to end a drag, the mouseup can trigger
     * a click event on the map. This causes unintended behavior like:
     * - Opening info windows
     * - Triggering map click handlers
     * - Interfering with the drag workflow
     *
     * SOLUTION:
     * Set a flag (skipNextClickRef.current = true) that lasts 100ms to suppress the next click.
     * The map click handler checks this flag and ignores the click if it's set.
     * We use a 100ms timeout because events are processed asynchronously and the click
     * might not happen immediately. After 100ms, we clear the flag to allow normal clicks.
     */
    if (skipNextClickRef) {
      skipNextClickRef.current = true

      // Clear the flag after 100ms in case no click happens (avoid blocking future clicks)
      setTimeout(() => {
        skipNextClickRef.current = false
      }, 100)
    }

    if (onDragEnd) {
      const markerPosition = marker.position
      onDragEnd({
        event,
        position: {
          latitude: typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat,
          longitude: typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng,
        },
      })
    }
  }

  function mouseDownHandler(event) {
    event.preventDefault()
    event.stopPropagation()

    mouseDown = true

    // Focus the marker since preventDefault blocks default focus behavior
    marker.focus()

    // Store the constraint origin
    const markerPosition = marker.position
    constraintOriginRef.current = {
      latitude: typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat,
      longitude: typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng,
    }
  }

  return { mouseMoveHandler, mouseUpHandler, mouseDownHandler }
}

/**
 * Manual dragging: Creates touch event handlers for manual drag with constraints
 * This enables mobile dragging when draggableDirections is specified
 */
function createTouchDragHandlers({
  constraintOriginRef,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  draggingRef,
  libraries,
  map,
  mapContainer,
  marker,
  onDrag,
  onDragEnd,
  sharedPopper,
  skipNextClickRef,
}) {
  let touchActive = false
  let lastTouch = null
  let animationFrameId = null
  let blurPreventionHandler = null

  function continuousUpdate() {
    if (touchActive && draggingRef.current && lastTouch) {
      updateMarkerFromClientCoordinates({
        clientX: lastTouch.clientX,
        clientY: lastTouch.clientY,
        constraintOriginRef,
        draggableConstraintOrigin,
        draggableDirections,
        draggableMaxDistance,
        draggableMinDistance,
        map,
        marker,
      })

      // Update label position if a label is showing
      if (sharedPopper && sharedPopper.isLabelOpenRef.current) {
        const markerRect = marker.getBoundingClientRect()
        sharedPopper.update({
          event: {
            clientX: markerRect.left + markerRect.width / 2,
            clientY: markerRect.top + markerRect.height / 2,
          },
        })
      }

      if (onDrag) {
        const markerPosition = marker.position
        onDrag({
          position: {
            latitude: typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat,
            longitude: typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng,
          },
        })
      }

      // Pan map if marker is near edge during continuous update
      moveMapIfNearEdge({ map, marker })

      animationFrameId = requestAnimationFrame(continuousUpdate)
    }
  }

  function touchMoveHandler(event) {
    if (!touchActive || event.touches.length !== 1 || !map || !libraries) return

    event.preventDefault()

    lastTouch = event.touches[0]

    if (!draggingRef.current) {
      draggingRef.current = true
      marker.setAttribute(ARIA_GRABBED, 'true')

      // Add dragging class to disable pointer events on markers
      if (mapContainer?.current) {
        mapContainer.current.classList.add('dragging')
      }

      // Prevent blur during touch drag
      blurPreventionHandler = (blurEvent) => {
        if (blurEvent.target === marker) {
          blurEvent.preventDefault()
          blurEvent.stopImmediatePropagation()
          requestAnimationFrame(() => {
            if (draggingRef.current) {
              marker.focus()
            }
          })
        }
      }

      marker.addEventListener('blur', blurPreventionHandler, { capture: true })

      // Start continuous update loop
      continuousUpdate()
    }

    // Pan map if marker is near edge
    moveMapIfNearEdge({ map, marker })
  }

  function touchEndHandler(event) {
    if (!touchActive) return

    touchActive = false
    const wasDragging = draggingRef.current
    draggingRef.current = false
    lastTouch = null
    marker.setAttribute(ARIA_GRABBED, 'false')

    // Remove blur prevention handler
    if (blurPreventionHandler) {
      marker.removeEventListener('blur', blurPreventionHandler, { capture: true })
      blurPreventionHandler = null
    }

    // Remove dragging class to re-enable pointer events on markers
    if (wasDragging && mapContainer?.current) {
      mapContainer.current.classList.remove('dragging')
    }

    // Cancel animation frame
    if (animationFrameId) {
      cancelAnimationFrame(animationFrameId)
      animationFrameId = null
    }

    // Prevent map click after drag ends
    if (skipNextClickRef) {
      skipNextClickRef.current = true

      setTimeout(() => {
        skipNextClickRef.current = false
      }, 100)
    }

    if (onDragEnd) {
      const markerPosition = marker.position
      onDragEnd({
        event,
        position: {
          latitude: typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat,
          longitude: typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng,
        },
      })
    }
  }

  function touchStartHandler(event) {
    if (event.touches.length !== 1) return

    event.preventDefault()
    event.stopPropagation()

    touchActive = true
    lastTouch = event.touches[0]

    // Focus the marker since preventDefault blocks default focus behavior
    marker.focus()

    // Store the constraint origin
    const markerPosition = marker.position
    constraintOriginRef.current = {
      latitude: typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat,
      longitude: typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng,
    }
  }

  return { touchMoveHandler, touchEndHandler, touchStartHandler }
}

/**
 * ============================================================================
 * MANUAL/CUSTOM DRAG IMPLEMENTATION
 * ============================================================================
 *
 * This section contains the manual drag implementation used when `draggableDirections` is specified.
 *
 * WHY MANUAL DRAGGING?
 * The native Google Maps API does not support directional constraints on marker dragging.
 * When `draggableDirections` is present, we need to:
 * - Constrain movement to specific directions (horizontal, vertical, or both)
 * - Enforce min/max distance constraints from an origin point
 *
 * HOW IT WORKS:
 * - Native Google Maps dragging (gmpDraggable) is DISABLED when draggableDirections is set
 * - Custom mouse and keyboard event handlers intercept drag operations
 * - Position constraints are applied via constrainPosition() before updating marker.position
 * - Edge panning is handled manually to auto-scroll the map during drag
 *
 * WHEN NATIVE DRAGGING IS USED:
 * - When draggable=true and draggableDirections is NOT specified
 * - Google Maps handles all drag logic natively via gmpDraggable property
 * ============================================================================
 */

// Manual dragging: Helper to extract position from marker
function getMarkerPosition(marker) {
  const markerPosition = marker.position
  return {
    latitude: typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat,
    longitude: typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng,
  }
}

// Manual dragging: Cleans up keyboard drag state and resets marker attributes
function cleanupKeyboardDragState({
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  marker,
  pressedKeysRef,
}) {
  keyboardDragInitialPosition.current = null
  pressedKeysRef.current.clear()

  if (keyboardDragMovementIntervalRef.current) {
    clearInterval(keyboardDragMovementIntervalRef.current)
    keyboardDragMovementIntervalRef.current = null
  }

  marker.style.zIndex = null
  marker.setAttribute(ARIA_GRABBED, 'false')
}

/**
 * Manual dragging: Continuously update marker position during keyboard drag
 *
 * WHY WE USE setInterval:
 * Keyboard events fire repeatedly while a key is held, but the rate varies by OS and browser.
 * Users often hold multiple arrow keys simultaneously (e.g., up+right for diagonal movement).
 * Using setInterval gives us:
 * 1. Consistent, smooth movement at KEYBOARD_DRAG_MOVEMENT_MS intervals (60fps)
 * 2. Proper handling of multiple simultaneous key presses
 * 3. Independence from browser/OS key repeat rates
 *
 * HOW IT WORKS:
 * 1. Tracks all currently pressed arrow keys in pressedKeysRef
 * 2. Every interval, calculates cumulative movement from all pressed keys
 * 3. Applies constraints (direction, min/max distance)
 * 4. Updates marker position and triggers callbacks (onDrag, edge panning)
 */
function handleKeyboardDragMovement({
  constraintOrigin,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  map,
  marker,
  moveMapCallback,
  onDrag,
  pressedKeysRef,
  sharedPopper,
}) {
  const zoom = map.getZoom()
  const step = KEYBOARD_DRAG_STEP_FACTOR / 2 ** (zoom + 2)

  return setInterval(() => {
    const markerPosition = marker.position
    const currentLatitude = typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat
    const currentLongitude = typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng

    const newPosition = {
      latitude: currentLatitude,
      longitude: currentLongitude,
    }

    if (pressedKeysRef.current.has('ArrowUp')) newPosition.latitude += step
    if (pressedKeysRef.current.has('ArrowDown')) newPosition.latitude -= step
    if (pressedKeysRef.current.has('ArrowLeft')) newPosition.longitude -= step
    if (pressedKeysRef.current.has('ArrowRight')) newPosition.longitude += step

    const constrainedPosition = constrainPosition({
      draggableDirections,
      newPosition,
      originPosition: draggableConstraintOrigin || constraintOrigin,
      maxDistance: draggableMaxDistance,
      minDistance: draggableMinDistance,
    })

    marker.position = {
      lat: constrainedPosition.latitude,
      lng: constrainedPosition.longitude,
    }

    // Update label position if a label is showing
    if (sharedPopper && sharedPopper.isLabelOpenRef.current) {
      const markerRect = marker.getBoundingClientRect()
      sharedPopper.update({
        event: {
          clientX: markerRect.left + markerRect.width / 2,
          clientY: markerRect.top + markerRect.height / 2,
        },
      })
    }

    if (onDrag) {
      onDrag({
        position: {
          latitude: constrainedPosition.latitude,
          longitude: constrainedPosition.longitude,
        },
      })
    }

    moveMapCallback()
  }, KEYBOARD_DRAG_MOVEMENT_MS)
}

// Manual dragging: Treats Enter key as a click for accessibility
function handleEnterKeyAsClick({ event, eventListeners }) {
  event.stopPropagation()
  if (eventListeners.click) {
    eventListeners.click(event)
  }
}

// Manual dragging: Handles arrow key presses during keyboard drag
function handleArrowKeysDuringDrag({
  constraintOrigin,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  event,
  keyboardDragMovementIntervalRef,
  map,
  marker,
  moveMapCallback,
  onDrag,
  pressedKeysRef,
  sharedPopper,
}) {
  event.preventDefault()
  event.stopPropagation()

  pressedKeysRef.current.add(event.code)

  if (!keyboardDragMovementIntervalRef.current) {
    keyboardDragMovementIntervalRef.current = handleKeyboardDragMovement({
      constraintOrigin,
      draggableConstraintOrigin,
      draggableDirections,
      draggableMaxDistance,
      draggableMinDistance,
      map,
      marker,
      moveMapCallback,
      onDrag,
      pressedKeysRef,
      sharedPopper,
    })
  }
}

// Manual dragging: Handles Escape key to cancel keyboard drag and restore original position
function handleEscapeToCancelDrag({
  event,
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  marker,
  metadata,
  onDragEnd,
  pressedKeysRef,
}) {
  marker.position = keyboardDragInitialPosition.current

  const position = getMarkerPosition(marker)

  // Call onDragEnd to clean up shadow circle
  if (onDragEnd) {
    onDragEnd({
      event,
      metadata,
      position,
      cancelled: true,
    })
  }

  cleanupKeyboardDragState({ keyboardDragInitialPosition, keyboardDragMovementIntervalRef, marker, pressedKeysRef })

  // Keep focus on the marker
  marker.focus()

  event.preventDefault()
  event.stopPropagation()
}

/**
 * Manual dragging: Complete keyboard drag at current position
 *
 * skipNextClickRef EXPLANATION:
 * When a user completes a keyboard drag with Space/Enter, the keypress can bubble up
 * and trigger a click event on the map. This causes unintended behavior like:
 * - Opening info windows
 * - Triggering map click handlers
 * - Interfering with the drag workflow
 *
 * SOLUTION:
 * Set a flag (skipNextClickRef.current = true) that lasts 100ms to suppress the next click.
 * The map click handler checks this flag and ignores the click if it's set.
 * We use a 100ms timeout because events are processed asynchronously and the click
 * might not happen immediately. After 100ms, we clear the flag to allow normal clicks.
 */
function handleSpaceOrEnterToCompleteDrag({
  event,
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  marker,
  metadata,
  onDragEnd,
  pressedKeysRef,
  skipNextClickRef,
}) {
  const position = getMarkerPosition(marker)

  // Prevent the map's onClick from firing after keyboard drag ends
  if (skipNextClickRef) {
    skipNextClickRef.current = true

    // Clear the flag after 100ms in case no click happens (avoid blocking future clicks)
    setTimeout(() => {
      skipNextClickRef.current = false
    }, 100)
  }

  if (onDragEnd) {
    onDragEnd({
      event,
      metadata,
      position,
    })
  }

  cleanupKeyboardDragState({ keyboardDragInitialPosition, keyboardDragMovementIntervalRef, marker, pressedKeysRef })

  event.preventDefault()
}

/**
 * Manual dragging: Start keyboard drag mode with Alt+Space or Alt+Enter
 *
 * WHY ALT KEY IS REQUIRED:
 * Space and Enter keys have default behaviors that would conflict with drag initiation:
 * - Enter: Triggers click events (used for activating buttons, links, etc.)
 * - Space: Scrolls the page down (default browser behavior)
 *
 * By requiring Alt to be held, we:
 * 1. Avoid conflicts with default keyboard behaviors
 * 2. Prevent accidental drag initiation
 * 3. Follow accessibility patterns for modifier keys (like Ctrl+C for copy)
 *
 * Without Alt:
 * - Users pressing Enter would start drag instead of clicking
 * - Users pressing Space would start drag instead of scrolling
 * This would break basic keyboard navigation.
 */
function handleAltSpaceOrEnterToStartDrag({ event, keyboardDragInitialPosition, marker }) {
  keyboardDragInitialPosition.current = marker.position

  marker.style.zIndex = 2 // Bring marker to front during drag
  marker.setAttribute(ARIA_GRABBED, 'true')

  event.preventDefault()
}

// Manual dragging: Main keyboard event handler for manual drag mode
function handleKeyDown({
  constraintOrigin,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  event,
  eventListeners,
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  map,
  marker,
  metadata,
  moveMapCallback,
  onDrag,
  onDragEnd,
  pressedKeysRef,
  sharedPopper,
  skipNextClickRef,
}) {
  const altKeyDown = event.altKey
  const escapeKeyDown = event.code === 'Escape'
  const enterKeyDown = event.code === 'Enter'
  const spaceKeyDown = event.code === 'Space'
  const spaceOrEnterKeyDown = spaceKeyDown || enterKeyDown
  const isDragging = Boolean(keyboardDragInitialPosition.current)

  // Treat the enter key as a click for keyboard accessibility
  if (enterKeyDown && !altKeyDown && !isDragging) {
    handleEnterKeyAsClick({ event, eventListeners })
    return
  }

  const arrowKeys = ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight']
  const isArrowKey = arrowKeys.includes(event.code)

  if (isArrowKey && isDragging) {
    handleArrowKeysDuringDrag({
      constraintOrigin,
      draggableConstraintOrigin,
      draggableDirections,
      draggableMaxDistance,
      draggableMinDistance,
      event,
      keyboardDragMovementIntervalRef,
      map,
      marker,
      moveMapCallback,
      onDrag,
      pressedKeysRef,
      sharedPopper,
    })
    return
  }

  if (escapeKeyDown && isDragging) {
    handleEscapeToCancelDrag({
      event,
      keyboardDragInitialPosition,
      keyboardDragMovementIntervalRef,
      marker,
      metadata,
      onDragEnd,
      pressedKeysRef,
    })
    return
  }

  if (spaceOrEnterKeyDown && isDragging) {
    handleSpaceOrEnterToCompleteDrag({
      event,
      keyboardDragInitialPosition,
      keyboardDragMovementIntervalRef,
      marker,
      metadata,
      onDragEnd,
      pressedKeysRef,
      skipNextClickRef,
    })
    return
  }

  if (altKeyDown && spaceOrEnterKeyDown) {
    handleAltSpaceOrEnterToStartDrag({ event, keyboardDragInitialPosition, marker })
  }
}

// Manual dragging: Handles key up events during keyboard drag
function handleKeyUp({ event, pressedKeysRef, keyboardDragMovementIntervalRef }) {
  const arrowKeys = ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight']
  if (arrowKeys.includes(event.code)) {
    pressedKeysRef.current.delete(event.code)
    if (pressedKeysRef.current.size === 0) {
      clearInterval(keyboardDragMovementIntervalRef.current)
      keyboardDragMovementIntervalRef.current = null
    }
  }
}

// Manual dragging: Calculates pan delta when marker is near edge
function calculatePanDelta({ bounds, threshold, x, y }) {
  let dx = 0
  let dy = 0

  if (x < threshold) {
    dx = x - threshold
  } else if (x > bounds.width - threshold) {
    dx = x - (bounds.width - threshold)
  }

  if (y < threshold) {
    dy = y - threshold
  } else if (y > bounds.height - threshold) {
    dy = y - (bounds.height - threshold)
  }

  return { dx, dy }
}

// Manual dragging: Sets map center for edge panning during drag
function setMapCenter({ center, dx, dy, latitudePerPixel, longitudePerPixel, map }) {
  // Use setCenter for instant centering without animation to avoid conflicts during continuous keyboard dragging.
  // This also ensures a smoother experience.
  const newLatitude = center.lat() - (dy / MAP_PAN_SCALE) * latitudePerPixel
  const newLongitude = center.lng() + (dx / MAP_PAN_SCALE) * longitudePerPixel
  map.setCenter({ lat: newLatitude, lng: newLongitude })
}

// Manual dragging: Creates callback for panning map during keyboard drag
function createMoveMapCallback({ map, marker }) {
  return () => {
    // Pan map if marker is near edge (for keyboard dragging)

    const mapDiv = map.getDiv()
    const bounds = mapDiv.getBoundingClientRect()

    // Get marker's pixel position
    const markerPosition = marker.position
    const latitude = typeof markerPosition.lat === 'function' ? markerPosition.lat() : markerPosition.lat
    const longitude = typeof markerPosition.lng === 'function' ? markerPosition.lng() : markerPosition.lng

    const markerBounds = map.getBounds()
    const topRight = markerBounds.getNorthEast()
    const bottomLeft = markerBounds.getSouthWest()

    const x = ((longitude - bottomLeft.lng()) / (topRight.lng() - bottomLeft.lng())) * bounds.width
    const y = ((topRight.lat() - latitude) / (topRight.lat() - bottomLeft.lat())) * bounds.height

    const { dx, dy } = calculatePanDelta({ bounds, threshold: EDGE_PAN_THRESHOLD, x, y })

    if (dx !== 0 || dy !== 0) {
      const center = map.getCenter()
      const latitudePerPixel = (topRight.lat() - bottomLeft.lat()) / bounds.height
      const longitudePerPixel = (topRight.lng() - bottomLeft.lng()) / bounds.width

      setMapCenter({ center, dx, dy, latitudePerPixel, longitudePerPixel, map })
    }
  }
}

// General: Returns the appropriate marker component based on marker type
function getDisplayMarker({
  chars,
  cluster,
  color,
  draggable,
  draggableDirections,
  focused,
  Icon,
  imageSrc,
  interactable,
  proximity,
  testId,
}) {
  if (draggableDirections) {
    return <ResizeHandleMarker color={color} draggableDirections={draggableDirections} />
  }

  if (cluster || imageSrc || proximity) {
    return (
      <RoundMarker
        chars={chars}
        cluster={cluster}
        color={color}
        draggable={draggable}
        draggableDirections={draggableDirections}
        focused={focused}
        Icon={Icon}
        imageSrc={imageSrc}
        interactable={interactable}
        proximity={proximity}
        testId={testId}
      />
    )
  }

  return (
    <TeardropMarker
      chars={chars}
      color={color}
      draggable={draggable}
      draggableDirections={draggableDirections}
      focused={focused}
      Icon={Icon}
      interactable={interactable}
      testId={testId}
    />
  )
}

/**
 * Manual dragging: Sets up all event listeners for manual drag mode
 * Includes mouse handlers, keyboard handlers, and focus/blur handlers
 */
function setupManualDragEventListeners({
  constraintOriginRef,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  draggingRef,
  eventListeners,
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  libraries,
  map,
  mapContainer,
  marker,
  metadataRef,
  onDragRef,
  onDragEndRef,
  pressedKeysRef,
  sharedPopper,
  skipNextClickRef,
}) {
  const moveMapCallback = createMoveMapCallback({ map, marker })

  const dragHandler = onDragRef.current || eventListeners.drag
  const { mouseMoveHandler, mouseUpHandler, mouseDownHandler } = createManualDragHandlers({
    constraintOriginRef,
    draggableConstraintOrigin,
    draggableDirections,
    draggableMaxDistance,
    draggableMinDistance,
    draggingRef,
    libraries,
    map,
    mapContainer,
    marker,
    onDrag: dragHandler
      ? (dragEvent) => {
          dragHandler({
            ...dragEvent,
            metadata: metadataRef.current,
          })
        }
      : undefined,
    onDragEnd: (dragEvent) => {
      if (onDragEndRef.current) {
        onDragEndRef.current({
          ...dragEvent,
          metadata: metadataRef.current,
        })
      }
    },
    sharedPopper,
    skipNextClickRef,
  })

  const { touchMoveHandler, touchEndHandler, touchStartHandler } = createTouchDragHandlers({
    constraintOriginRef,
    draggableConstraintOrigin,
    draggableDirections,
    draggableMaxDistance,
    draggableMinDistance,
    draggingRef,
    libraries,
    map,
    mapContainer,
    marker,
    onDrag: dragHandler
      ? (dragEvent) => {
          dragHandler({
            ...dragEvent,
            metadata: metadataRef.current,
          })
        }
      : undefined,
    onDragEnd: (dragEvent) => {
      if (onDragEndRef.current) {
        onDragEndRef.current({
          ...dragEvent,
          metadata: metadataRef.current,
        })
      }
    },
    sharedPopper,
    skipNextClickRef,
  })

  const keyDownHandler = (event) => {
    handleKeyDown({
      constraintOrigin: constraintOriginRef.current,
      draggableConstraintOrigin,
      draggableDirections,
      draggableMaxDistance,
      draggableMinDistance,
      event,
      eventListeners,
      keyboardDragInitialPosition,
      keyboardDragMovementIntervalRef,
      map,
      marker,
      metadata: metadataRef.current,
      moveMapCallback,
      onDrag: dragHandler,
      onDragEnd: onDragEndRef.current,
      pressedKeysRef,
      sharedPopper,
      skipNextClickRef,
    })
  }

  const keyUpHandler = (event) => {
    handleKeyUp({ event, pressedKeysRef, keyboardDragMovementIntervalRef })
  }

  const blurHandler = () => {
    marker.classList.remove('focus')

    if (keyboardDragInitialPosition.current) {
      keyboardDragInitialPosition.current = null
      pressedKeysRef.current.clear()

      if (keyboardDragMovementIntervalRef.current) {
        clearInterval(keyboardDragMovementIntervalRef.current)
        keyboardDragMovementIntervalRef.current = null
      }

      marker.setAttribute(ARIA_GRABBED, 'false')
    }
  }

  const focusHandler = () => {
    marker.classList.add('focus')
  }

  // Add event listeners
  marker.addEventListener('mousedown', mouseDownHandler)
  marker.addEventListener('keydown', keyDownHandler, { capture: true })
  marker.addEventListener('keyup', keyUpHandler)
  marker.addEventListener('blur', blurHandler)
  marker.addEventListener('focus', focusHandler)
  document.addEventListener('mousemove', mouseMoveHandler)
  document.addEventListener('mouseup', mouseUpHandler)

  // Add touch event listeners for mobile support
  marker.addEventListener('touchstart', touchStartHandler, { passive: false })
  document.addEventListener('touchmove', touchMoveHandler, { passive: false })
  document.addEventListener('touchend', touchEndHandler)

  // Make marker focusable and set ARIA attributes
  marker.setAttribute('tabindex', '0')
  marker.setAttribute('role', 'button')
  marker.setAttribute(ARIA_GRABBED, 'false')

  // Return cleanup function
  return () => {
    marker.removeEventListener('mousedown', mouseDownHandler)
    marker.removeEventListener('keydown', keyDownHandler, { capture: true })
    marker.removeEventListener('keyup', keyUpHandler)
    marker.removeEventListener('blur', blurHandler)
    marker.removeEventListener('focus', focusHandler)
    document.removeEventListener('mousemove', mouseMoveHandler)
    document.removeEventListener('mouseup', mouseUpHandler)

    // Remove touch event listeners
    marker.removeEventListener('touchstart', touchStartHandler)
    document.removeEventListener('touchmove', touchMoveHandler)
    document.removeEventListener('touchend', touchEndHandler)

    if (keyboardDragMovementIntervalRef.current) {
      clearInterval(keyboardDragMovementIntervalRef.current)
    }
  }
}

const Marker = forwardRef((props, ref) => {
  const {
    ariaLabel,
    chars,
    cluster,
    color,
    draggable,
    draggableConstraintOrigin,
    draggableDirections,
    draggableMaxDistance,
    draggableMinDistance,
    focused,
    Icon,
    id,
    imageSrc,
    latitude,
    longitude,
    metadata,
    onDrag,
    onDragEnd,
    proximity,
    testId,
    title,
  } = props

  const contentRef = useRef(null)
  const gmpEventListenersRef = useRef([])
  const eventListenersRef = useRef([])
  const constraintOriginRef = useRef({ latitude, longitude })
  const keyboardDragInitialPosition = useRef()
  const keyboardDragMovementIntervalRef = useRef()
  const pressedKeysRef = useRef(new Set())
  const draggingRef = useRef(false)
  // Store callbacks in refs to prevent recreating event handlers on every render
  // This improves performance and prevents listeners from being removed/re-added during drag
  const onDragRef = useRef(onDrag)
  const onDragEndRef = useRef(onDragEnd)
  const metadataRef = useRef(metadata)
  const cleanupRef = useRef(null)
  const { googleApiKey, map, mapContainer, skipNextClickRef } = useMap()
  const { libraries } = useLibraries({ googleApiKey })

  const { eventListeners, initialPropsRef, interactable, marker, setMarker, sharedPopper } = useMarker(props, ref)

  // Keep refs in sync with latest callback values
  useEffect(() => {
    onDragRef.current = onDrag
    onDragEndRef.current = onDragEnd
    metadataRef.current = metadata
  }, [onDrag, onDragEnd, metadata])

  if (contentRef.current === null) {
    contentRef.current = createContentElement()
  }

  // General: Create the marker instance
  useEffect(() => {
    let advancedMarker
    if (map && libraries) {
      const initialOptions = createInitialOptions({ contentRef, initialPropsRef, map })

      advancedMarker = new libraries.marker.AdvancedMarkerElement(initialOptions)

      if (id) {
        advancedMarker.id = id
      }

      configureMarkerStyling({ marker: advancedMarker, initialPropsRef })

      setMarker(advancedMarker)
    }

    return () => {
      if (advancedMarker) {
        advancedMarker.map = null
      }
    }
  }, [id, initialPropsRef, libraries, map, setMarker])

  // General: Add event listeners (includes native drag events if applicable)
  useEffect(() => {
    if (marker) {
      clearEventListeners({ eventListenersRef, gmpEventListenersRef, marker })
      addEventListeners({ eventListeners, eventListenersRef, gmpEventListenersRef, marker })
    }

    return () => {
      clearEventListeners({ eventListenersRef, gmpEventListenersRef, marker })
    }
  }, [eventListeners, marker])

  // General: Update marker options (disables native dragging when draggableDirections is present)
  useEffect(() => {
    if (marker) {
      updateMarkerAccessibility({ ariaLabel, draggable, interactable, marker, title })
      updateMarkerDraggableState({ draggable, marker })
      updateMarkerTranslate({ cluster, draggableDirections, imageSrc, marker, proximity })

      marker.gmpClickable = interactable
      // Native dragging: Disabled when draggableDirections is present (manual drag used instead)
      marker.gmpDraggable = draggable && !draggableDirections
    }
  }, [
    ariaLabel,
    cluster,
    draggable,
    draggableDirections,
    imageSrc,
    interactable,
    latitude,
    longitude,
    marker,
    proximity,
    title,
  ])

  // General: Update marker position
  useEffect(() => {
    if (marker) {
      marker.position = { lat: latitude, lng: longitude }
      constraintOriginRef.current = { latitude, longitude }
    }
  }, [latitude, longitude, marker])

  /**
   * Manual dragging: Setup manual drag event listeners when draggableDirections is present
   * This effect only runs when manual dragging is needed (draggableDirections is set)
   * When this is active, native dragging (gmpDraggable) is disabled
   */
  useEffect(() => {
    if (!marker || !draggable || !draggableDirections || !map || !libraries) {
      return undefined
    }

    // If cleanup already exists, reuse it instead of creating new handlers
    if (!cleanupRef.current) {
      cleanupRef.current = setupManualDragEventListeners({
        constraintOriginRef,
        draggableConstraintOrigin,
        draggableDirections,
        draggableMaxDistance,
        draggableMinDistance,
        draggingRef,
        eventListeners,
        keyboardDragInitialPosition,
        keyboardDragMovementIntervalRef,
        libraries,
        map,
        mapContainer,
        marker,
        metadataRef,
        onDragRef,
        onDragEndRef,
        pressedKeysRef,
        sharedPopper,
        skipNextClickRef,
      })
    }

    return () => {
      // CRITICAL: Don't remove event listeners if drag is active
      // Removing listeners mid-drag would break the drag operation - mousemove/touchmove/mouseup/touchend
      // events would no longer be captured, leaving the marker in a stuck dragging state
      // eslint-disable-next-line react-hooks/exhaustive-deps -- We intentionally check the ref at cleanup time
      if (draggingRef.current) {
        return
      }

      if (cleanupRef.current) {
        cleanupRef.current()
        cleanupRef.current = null
      }
    }
  }, [
    draggable,
    draggableConstraintOrigin,
    draggableDirections,
    draggableMaxDistance,
    draggableMinDistance,
    eventListeners,
    libraries,
    map,
    mapContainer,
    marker,
    sharedPopper,
    skipNextClickRef,
  ])

  const displayMarker = getDisplayMarker({
    chars,
    cluster,
    color,
    draggable,
    draggableDirections,
    focused,
    Icon,
    imageSrc,
    interactable,
    proximity,
    testId,
  })

  return createPortal(displayMarker, contentRef.current)
})

Marker.displayName = 'Marker'

export default Marker

Marker.propTypes = {
  ariaLabel: PropTypes.string.isRequired,
  chars: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  cluster: PropTypes.bool,
  color: PropTypes.oneOf(['blue', 'gray', 'green', 'purple', 'red', 'yellow']),
  draggable: PropTypes.bool,
  draggableConstraintOrigin: PropTypes.shape({
    latitude: PropTypes.number.isRequired,
    longitude: PropTypes.number.isRequired,
  }),
  draggableDirections: draggableDirectionsValidator,
  draggableMaxDistance: PropTypes.number,
  draggableMinDistance: PropTypes.number,
  focused: PropTypes.bool,
  Icon: PropTypes.func,
  id: PropTypes.string,
  imageSrc: PropTypes.string,
  info: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),
  label: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),
  latitude: PropTypes.number.isRequired,
  longitude: PropTypes.number.isRequired,
  metadata: PropTypes.any,
  onBlur: PropTypes.func,
  onClick: PropTypes.func,
  onDrag: PropTypes.func,
  onDragEnd: PropTypes.func,
  onFocus: PropTypes.func,
  onInfoClosed: PropTypes.func,
  onMouseEnter: PropTypes.func,
  onMouseLeave: PropTypes.func,
  proximity: PropTypes.bool,
  testId: PropTypes.string,
  title: PropTypes.string,
}
