import { useEffect, useState } from 'react'
import { i18n } from '@fs/zion-locale'
import { Loader } from '@googlemaps/js-api-loader'
import PropTypes from 'prop-types'

const LIBRARIES_TO_IMPORT = ['core', 'maps', 'marker']
// This key is secured through the Google Cloud Developer Console.
// See: https://familysearch.slack.com/archives/C0FPL3ZL7/p1645566927712379
// This API key should not be used by anyone at any time.
const STORYBOOK_GOOGLE_API_KEY = 'AIzaSyAZe2HPoqmuPTkxrNv-gdY2egzM7wIHYYo'

export default function useLibraries({ googleApiKey }) {
  const [error, setError] = useState()
  const [libraries, setLibraries] = useState()

  // Load the Google Maps JavaScript API libraries.
  useEffect(() => {
    let cancelled = false

    let language = i18n.language
    if (language === 'zh-hans') {
      language = 'zh-CN'
    } else if (language === 'zh') {
      language = 'zh-TW'
    }

    const loader = new Loader({
      apiKey: process.env.STORYBOOK === 'true' && !googleApiKey ? STORYBOOK_GOOGLE_API_KEY : googleApiKey,
      language,
      version: 'weekly',
    })

    Promise.all(LIBRARIES_TO_IMPORT.map((library) => loader.importLibrary(library)))
      .then((importedLibraries) => {
        if (cancelled) {
          return
        }

        setLibraries(
          LIBRARIES_TO_IMPORT.reduce((librariesToSet, library, index) => {
            librariesToSet[library] = importedLibraries[index]

            return librariesToSet
          }, {})
        )
      })
      .catch((loaderError) => {
        if (cancelled) {
          return
        }

        setError(loaderError)
      })

    return () => {
      cancelled = true
    }
  }, [googleApiKey])

  return { error, libraries }
}

useLibraries.propTypes = {
  googleApiKey: PropTypes.string,
}
